import{_ as i,o as a,c as e,ae as t}from"./chunks/framework.RRduUuAx.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"szu/network/chapter-7.md","filePath":"szu/network/chapter-7.md"}'),o={name:"szu/network/chapter-7.md"};function r(u,l,n,h,s,E){return a(),e("div",null,[...l[0]||(l[0]=[t('<h2 id="一-、无线网络" tabindex="-1">(一)、无线网络 <a class="header-anchor" href="#一-、无线网络" aria-label="Permalink to &quot;(一)、无线网络&quot;">​</a></h2><ol><li>无线网络基本结构 <ul><li>1.无线主机</li><li>2.无线链路</li><li>3.基站。基站在有线网络中没有明确的对应设备，负责向与之相关联的无线主机发送数据和接收主机发送的数据。 <ul><li>蜂窝网络中的蜂窝塔和 IEEE 802.11 无线局域网中的接入点（AP）都是基站的例子。</li></ul></li><li>4.网络基础设施。 <ul><li>通常是大规模有线网络，如 Internet、公司网络或电话网络等</li><li>无线链路将位于网络边缘的主机连接到基站，基站与更大的网络基础设施相连接，因此基站在无线主机和网络基础设施之间起着链路层中继作用。</li></ul></li></ul></li><li>无线链路与无线网络特性 <ul><li>如果用 IEEE 802.11 无线局域网络，替代原有网络中的有线以太网，则需要用无线网卡替代主机的有线网卡，用接入点替代以太网交换机，但网络层及其以上层次不需要有任何变化。</li><li>无线链路有别与有线链路的主要表现 <ul><li>1.信号强度的衰减</li><li>2.干扰</li><li>3.多路径传播</li></ul></li></ul></li></ol><h2 id="二-、移动网络" tabindex="-1">(二)、移动网络 <a class="header-anchor" href="#二-、移动网络" aria-label="Permalink to &quot;(二)、移动网络&quot;">​</a></h2><ol><li>移动网络基本原理 <ul><li>无线网络不一定是移动网络，但移动网络一定是无线网络。移动网络中的移动结点是随着时间改变其与网络连接位置的结点，并且一定采用无线通信技术。</li><li>1.从网络层的角度分析用户的移动性</li><li>2.移动结点的地址始终保持不变的重要性</li><li>3.可用的有线基础设施的支持</li></ul></li><li>寻址 <ul><li>1.外部网络可以通过向所有其他网络发通告，告诉它们该移动结点正在它的网络中。</li><li>2.将移动性功能从网络核心搬到网络边缘，由该移动结点的归属网络来实现。</li></ul></li><li>移动结点的路由选择 <ul><li>1.移动结点的间接路由选择</li><li>2.移动结点的直接路由选择</li></ul></li></ol><h2 id="三-、无线局域网-ieee-802-11" tabindex="-1">(三)、无线局域网 IEEE 802.11 <a class="header-anchor" href="#三-、无线局域网-ieee-802-11" aria-label="Permalink to &quot;(三)、无线局域网 IEEE 802.11&quot;">​</a></h2><p>IEEE 802 家族是由一系列局域网（LAN）技术规范所组成的。IEEE 802.11 发表于 1997 年，是原始标准，支持速率 2Mbit/s，工作在 2.4GHz 的 ISM 频段。</p><ol><li>IEEE 802.11 体系结构 <ul><li>基站，又称为接入点</li><li>基本服务集</li></ul></li><li>IEEE 802.11 的 MAC 协议</li><li>IEEE 802.11 帧 <ul><li>地址字段</li><li>序号、持续期和帧控制字段</li></ul></li></ol><h2 id="四-、蜂窝网络" tabindex="-1">(四)、蜂窝网络 <a class="header-anchor" href="#四-、蜂窝网络" aria-label="Permalink to &quot;(四)、蜂窝网络&quot;">​</a></h2><ol><li>蜂窝网络体系结构</li><li>蜂窝网络中的移动性管理</li><li>移动通信 2G/3G/4G/5G 网络</li></ol><h2 id="五-、移动-ip-网络" tabindex="-1">(五)、移动 IP 网络 <a class="header-anchor" href="#五-、移动-ip-网络" aria-label="Permalink to &quot;(五)、移动 IP 网络&quot;">​</a></h2><p>移动 IP 由 IETF 开发，允许计算机移动到外地时，仍然保留其原来的 IP 地址。</p><ol><li>代理发现 <ul><li>代理通告</li><li>代理请求</li></ul></li><li>向归属代理注册</li></ol><h2 id="六-、其他典型无线网络简介" tabindex="-1">(六)、其他典型无线网络简介 <a class="header-anchor" href="#六-、其他典型无线网络简介" aria-label="Permalink to &quot;(六)、其他典型无线网络简介&quot;">​</a></h2><ol><li>WiMax</li><li>蓝牙</li><li>ZigBee</li></ol>',14)])])}const p=i(o,[["render",r]]);export{d as __pageData,p as default};
